// CalcuQuote (Ltd) vs Claude API (Inc) Comparison Framework
//
// See ../calcuquote-vs-claude-api-comparison.md for the full workflow + business
// rules. This script consumes pre-parsed CalcuQuote BOM (quotes.json), dumped
// system VQs (system-vqs.csv), and RFQ-line/MPN data (rfq-lines.csv) — all
// generated by the orchestrator. Emits the 10-tab Excel comparison + emails it.
//
// Usage (after running fetch-calcuquote-email.js + the DB dump steps):
//   node compare-cq-vs-api.js \
//     --rfq <searchKey>                # e.g. 1132586 — used to pick scratch dir + label
//     [--scratch <dir>]                # default: ~/workspace/scratch/cq-rfq-<rfq>
//     [--label <name>]                 # used in output filename (e.g. "JohnsonControls")
//     [--email-to <addr>]              # default: jake.harris@Astutegroup.com
//     [--manual-channels "ch1,ch2"]    # default: "TI (MFR direct),Coilcraft (MFR)"
//     [--no-email]                     # skip email send
//
// Validated on RFQ 1132586 / Johnson Controls (2026-05-13).

const fs = require('fs');
const path = require('path');
const ExcelJS = require('exceljs');
const { createNotifier } = require('/home/analytics_user/workspace/astute-workinstructions/shared/notifier');
const { canonicalMfr } = require('/home/analytics_user/workspace/astute-workinstructions/shared/mfr-equivalence');

function arg(name, fallback) {
  const i = process.argv.indexOf('--' + name);
  if (i === -1) return fallback;
  return process.argv[i + 1];
}
function flagSet(name) { return process.argv.includes('--' + name); }

const RFQ_KEY  = arg('rfq');
if (!RFQ_KEY) {
  console.error('--rfq <searchKey> is required (e.g. --rfq 1132586). See header for usage.');
  process.exit(1);
}
const SCRATCH  = arg('scratch', `/home/analytics_user/workspace/scratch/cq-rfq-${RFQ_KEY}`);
const LABEL    = arg('label', `RFQ-${RFQ_KEY}`);
const EMAIL_TO = arg('email-to', 'jake.harris@Astutegroup.com');
const SKIP_EMAIL = flagSet('no-email');
const MANUAL_OVERRIDE = arg('manual-channels');

const BOM_QUOTES_PATH = path.join(SCRATCH, 'quotes.json');
const SYSTEM_VQS_PATH = path.join(SCRATCH, 'system-vqs.csv');
const RFQ_LINES_PATH  = path.join(SCRATCH, 'rfq-lines.csv');
const OUT_XLSX        = path.join(SCRATCH, `${LABEL}-Inc-vs-Ltd-${new Date().toISOString().slice(0, 10)}.xlsx`);
const EMAIL_SUBJECT   = `${LABEL} — Inc vs Ltd comparison`;

console.log(`CalcuQuote vs Claude API Comparison`);
console.log(`  RFQ:        ${RFQ_KEY}`);
console.log(`  Scratch:    ${SCRATCH}`);
console.log(`  Output:     ${OUT_XLSX}`);
console.log(`  Email to:   ${EMAIL_TO}${SKIP_EMAIL ? ' (SKIPPED via --no-email)' : ''}`);
for (const p of [BOM_QUOTES_PATH, SYSTEM_VQS_PATH, RFQ_LINES_PATH]) {
  if (!fs.existsSync(p)) {
    console.error(`Missing required input: ${p}\nRun fetch-calcuquote-email.js and the DB dump (see workflow .md Steps 2–5) first.`);
    process.exit(1);
  }
}

// ────────── helpers ──────────
const normMpn = m => String(m || '').trim().toUpperCase().replace(/\s+/g, '');
// MFR canonicalization via shared library: collapses ONSEMI/ON SEMICONDUCTOR,
// KYOCERA AVX/KYOCERA AVX COMPONENTS, MURATA/MURATA ELECTRONICS, etc., and
// walks acquisition chains (Linear → ADI, Atmel → Microchip, etc.).
const normMfr = m => canonicalMfr(m) || String(m || '').trim().toUpperCase();
const toNum   = x => {
  if (x == null || x === '') return null;
  const n = typeof x === 'number' ? x : parseFloat(String(x).replace(/,/g, ''));
  return Number.isFinite(n) ? n : null;
};

function normSupplier(s) {
  const u = String(s || '').trim().toUpperCase();
  if (u === 'MYARROW')           return 'Arrow — MyArrow (US contract portal)';
  if (u === 'ARROW AMERICAS')    return 'Arrow — Americas (US catalog)';
  if (u === 'ARROW ELECTRONICS') return 'Arrow — generic (sys API)';
  if (u === 'AVNET')                                 return 'Avnet — generic';
  if (u === 'AVNETABACUS' || u === 'AVNET ABACUS')   return 'Avnet Abacus (EMEA)';
  if (u === 'AVNETEBV'    || u === 'AVNET EBV')      return 'Avnet EBV (EMEA)';
  if (u === 'AVNETSILICA' || u === 'AVNET SILICA')   return 'Avnet Silica (EMEA)';
  if (u === 'RUTRONIK')          return 'Rutronik (EMEA parent)';
  if (u === 'RUTRONIK INC.')     return 'Rutronik Inc. (US arm)';
  if (u === 'MOUSER')            return 'Mouser';
  if (u === 'DIGIKEY' || u === 'DIGI-KEY ELECTRONICS') return 'Digi-Key';
  if (u === 'TTI'     || u === 'TTI INC')            return 'TTI';
  if (u === 'FUTURE'  || u === 'FUTURE ELECTRONICS CORPORATION') return 'Future';
  if (u === 'NEWARK'  || u === 'NEWARK IN ONE (ELEMENT 14)')     return 'Newark (US e14)';
  if (u === 'FARNELL' || u === 'FARNELL ELEMENT 14')             return 'Farnell (UK e14)';
  if (u === 'SAMTEC'  || u === 'SAMTEC INC')         return 'Samtec (MFR)';
  if (u === 'SAGER'   || u === 'SAGER - V3004')      return 'Sager (US franchise)';
  if (u === 'ROCHESTER' || u === 'ROCHESTER ELECTRONICS, LLC')   return 'Rochester (authorized)';
  if (u === 'COILCRAFT')        return 'Coilcraft (MFR)';
  if (u === 'TEXAS INSTRUMENTS') return 'TI (MFR direct)';
  if (u === 'POWELLELECTRONICS' || u === 'POWELL ELECTRONICS') return 'Powell (US)';
  if (u === 'SCHUKAT')           return 'Schukat (EMEA)';
  if (u === 'VERICAL')           return 'Verical (Arrow catalog agg)';
  if (u === 'MASTER ELECTRONICS') return 'Master (US broker)';
  if (u === 'WALDOM ELECTRONICS') return 'Waldom (US broker)';
  return s;
}

function parseCsv(text) {
  const lines = text.split(/\r?\n/).filter(l => l.length);
  const header = parseLine(lines[0]);
  return lines.slice(1).map(l => {
    const f = parseLine(l);
    const o = {};
    header.forEach((h, i) => { o[h] = f[i]; });
    return o;
  });
}
function parseLine(l) {
  const out = []; let cur = ''; let q = false;
  for (let i = 0; i < l.length; i++) {
    const c = l[i];
    if (q) {
      if (c === '"' && l[i + 1] === '"') { cur += '"'; i++; }
      else if (c === '"') { q = false; }
      else { cur += c; }
    } else {
      if (c === ',') { out.push(cur); cur = ''; }
      else if (c === '"') { q = true; }
      else { cur += c; }
    }
  }
  out.push(cur);
  return out;
}

// ────────── load data ──────────
const bom      = JSON.parse(fs.readFileSync(BOM_QUOTES_PATH, 'utf8'));
const vqs      = parseCsv(fs.readFileSync(SYSTEM_VQS_PATH, 'utf8'));
const rfqLines = parseCsv(fs.readFileSync(RFQ_LINES_PATH, 'utf8'));

// AVL index
const acceptedIdx = new Map(); // normMpn → [{lineId, cpc, desc, qty, mfr}]
const onAvlSet = new Set();
const lineInfoById = new Map();
for (const r of rfqLines) {
  const lid = r.line_id;
  if (!lineInfoById.has(lid)) {
    lineInfoById.set(lid, { cpc: r.cpc || '', desc: r.line_desc || '', qty: toNum(r.line_qty) });
  }
  if (r.accepted_mpn) {
    const k = normMpn(r.accepted_mpn);
    onAvlSet.add(k);
    if (!acceptedIdx.has(k)) acceptedIdx.set(k, []);
    acceptedIdx.get(k).push({ lineId: lid, cpc: lineInfoById.get(lid).cpc, desc: lineInfoById.get(lid).desc });
  }
}

// Channels populated by MANUAL VQ loads on the Inc side, not by API enrichment.
// Excluded from "API-only" coverage/win stats so the comparison vs Ltd is fair
// (Ltd's CalcuQuote also doesn't reach MFR-direct manual channels). Override
// per-RFQ via --manual-channels "ch1,ch2" if a new RFQ has different manual loads.
const INC_MANUAL_CHANNELS = new Set(
  MANUAL_OVERRIDE
    ? MANUAL_OVERRIDE.split(',').map(s => s.trim())
    : ['TI (MFR direct)', 'Coilcraft (MFR)']
);
const isManualIncChannel = v => INC_MANUAL_CHANNELS.has(v);

// Inc by MPN → vendor → [{qty, cost, leadTime, rfq}]
const incByMpn = new Map();
for (const v of vqs) {
  const k = normMpn(v.mpn);
  const cost = toNum(v.cost), qty = toNum(v.qty);
  if (!k || cost == null || cost === 0 || qty == null) continue;
  if (!incByMpn.has(k)) incByMpn.set(k, { rawMpn: v.mpn, vendors: new Map() });
  const m = incByMpn.get(k).vendors;
  const vend = normSupplier(v.vendor_name) || v.vendor_name;
  if (!m.has(vend)) m.set(vend, []);
  m.get(vend).push({ qty, cost, leadTime: v.lead_time, dateCode: v.date_code, rfq: v.chuboe_rfq_id });
}

// Ltd by MPN
const ltdByMpn = new Map();
for (const b of bom) {
  const k = normMpn(b.selectedMpn);
  const cost = toNum(b.rfqUnit);
  const qty = toNum(b.totalQty) || toNum(b.totalDemand);
  if (!k || cost == null) continue;
  if (!ltdByMpn.has(k)) ltdByMpn.set(k, { rawMpn: b.selectedMpn, all: [], best: null });
  const slot = ltdByMpn.get(k);
  const ltdNotesLower = String(b.leadTimeNotes || '').toLowerCase();
  const leadClass = /in stock/.test(ltdNotesLower) ? 'STOCK'
    : /week|day|wk|lead time|short \d/.test(ltdNotesLower) ? 'LT'
    : 'UNKNOWN';
  const row = {
    vendor:    normSupplier(b.supplier) || b.supplier,
    cost, qty, leadClass,
    leadTime:  b.mfgLeadTime, leadTimeNotes: b.leadTimeNotes,
    mfgr:      b.selectedMfgr, mfrNorm: normMfr(b.selectedMfgr),
    description: b.description, rfqMpn: b.rfqMpn,
    rfqTarget: toNum(b.rfqTargetPrice), demand: toNum(b.totalDemand)
  };
  slot.all.push(row);
  if (!slot.best || row.cost < slot.best.cost) slot.best = row;
}

// ────────── helper: pick Inc volume-comparable row ──────────
function pickIncVolumeBid(mpnKey, ltdQty) {
  const slot = incByMpn.get(mpnKey);
  if (!slot) return null;
  let bestRow = null, bestVendor = null, bestTag = null;
  for (const [vendor, rs] of slot.vendors) {
    const sorted = rs.slice().sort((a, b) => a.qty - b.qty);
    let pick = null, tag = 'STRETCH';
    if (ltdQty) {
      for (const r of sorted) {
        if (r.qty >= ltdQty * 0.95) { pick = r; tag = 'VOLUME'; break; }
      }
    }
    if (!pick) { pick = sorted[sorted.length - 1]; tag = (ltdQty && pick.qty < ltdQty * 0.95) ? 'STRETCH' : 'VOLUME'; }
    if (!bestRow || pick.cost < bestRow.cost) { bestRow = pick; bestVendor = vendor; bestTag = tag; }
  }
  return { row: bestRow, vendor: bestVendor, tag: bestTag };
}

function classifyInc(leadTimeText) {
  const n = String(leadTimeText || '').trim().toLowerCase();
  if (!n) return 'STOCK?';
  if (/week|day|wk|lead/.test(n)) return 'LT';
  return 'UNKNOWN';
}

function isApples(ltdClass, incClass, incTag) {
  const incExplicitLt = incClass === 'LT';
  const incVolumeStock = (incClass === 'STOCK?' || incClass === 'STOCK') && incTag === 'VOLUME';
  if (ltdClass === 'LT'    && (incExplicitLt || incVolumeStock)) return true;
  if (ltdClass === 'STOCK' && (incClass === 'STOCK' || incVolumeStock)) return true;
  return false;
}

// ────────── head-to-head rows (one per MPN) ──────────
const allMpns = new Set([...incByMpn.keys(), ...ltdByMpn.keys()]);
const rows = [];

for (const k of allMpns) {
  const incHas = incBreaksHas(k);
  const ltdHas = ltdByMpn.has(k);
  const ltd = ltdHas ? ltdByMpn.get(k) : null;
  const ltdRow = ltd ? ltd.best : null;
  const ltdQty = ltdRow ? (ltdRow.qty || ltdRow.demand) : null;
  const incPick = incHas ? pickIncVolumeBid(k, ltdQty) : null;

  let winner, savingsPct = null, savingsDollars = null;
  const incRow = incPick ? incPick.row : null;
  const incVendor = incPick ? incPick.vendor : '';
  const incTag = incPick ? incPick.tag : '';
  const incClass = incRow ? classifyInc(incRow.leadTime) : '';
  const ltdClass = ltdRow ? ltdRow.leadClass : '';
  let bucketTag = 'N/A'; // CLEAN_APPLES | STRETCH | ORANGES | INC_ONLY | LTD_ONLY

  if (incHas && ltdHas) {
    const ic = incRow.cost, lc = ltdRow.cost;
    const delta = lc - ic;
    if (Math.abs(delta) / Math.max(ic, lc) < 0.005) winner = 'TIE';
    else if (lc < ic) winner = 'Ltd';
    else winner = 'Inc';
    savingsPct = (Math.max(ic, lc) - Math.min(ic, lc)) / Math.max(ic, lc);
    const demandQty = ltdRow.demand || ltdRow.qty || 0;
    savingsDollars = Math.abs(delta) * demandQty;
    if (incTag !== 'VOLUME') bucketTag = 'STRETCH';
    else if (!isApples(ltdClass, incClass, incTag)) bucketTag = 'ORANGES';
    else bucketTag = 'CLEAN_APPLES';
  } else if (incHas) {
    winner = 'Inc-only'; bucketTag = 'INC_ONLY';
  } else {
    winner = 'Ltd-only'; bucketTag = 'LTD_ONLY';
  }

  // CPC + on-AVL lookups
  const cpcMatches = acceptedIdx.get(k) || [];
  const cpcs = [...new Set(cpcMatches.map(x => x.cpc).filter(Boolean))];
  const lineIds = [...new Set(cpcMatches.map(x => String(x.lineId)))];
  const lineDescs = [...new Set(cpcMatches.map(x => x.desc).filter(Boolean))];
  const onAvl = cpcMatches.length > 0;

  // For Inc-only, pick best price (any qty) for display
  let displayIncRow = incRow, displayIncVendor = incVendor;
  if (winner === 'Inc-only' && !incRow && incHas) {
    let bestIncCost = Infinity, bestIncVend = '', bestIncQty = null, bestIncLT = '';
    for (const [vend, rs] of incBreaksByMpn(k).entries()) {
      const minR = rs.reduce((a, b) => a.cost < b.cost ? a : b);
      if (minR.cost < bestIncCost) { bestIncCost = minR.cost; bestIncVend = vend; bestIncQty = minR.qty; bestIncLT = minR.leadTime; }
    }
    displayIncRow = { cost: bestIncCost, qty: bestIncQty, leadTime: bestIncLT, rfq: '' };
    displayIncVendor = bestIncVend;
  }

  const incVendorSet = new Set(incHas ? [...incBreaksByMpn(k).keys()] : []);
  const ltdVendorSet = new Set(ltd ? ltd.all.map(x => x.vendor) : []);

  rows.push({
    mpn: (incHas ? incByMpn.get(k).rawMpn : ltd.rawMpn),
    winner, bucketTag, breakTag: incTag, applesIs: isApples(ltdClass, incClass, incTag),
    incClass, ltdClass,
    savingsPct, savingsDollars,
    demandQty:   ltdRow ? (ltdRow.demand || ltdRow.qty) : null,
    description: ltdRow ? ltdRow.description : '',
    mfgr:        ltdRow ? ltdRow.mfgr : (incHas ? '' : ''),
    mfrNorm:     ltdRow ? ltdRow.mfrNorm : '',
    rfqTargetUsd: ltdRow ? ltdRow.rfqTarget : null,
    incVolVendor: displayIncVendor,
    incVolCost:   displayIncRow ? displayIncRow.cost : null,
    incVolQty:    displayIncRow ? displayIncRow.qty : null,
    incVolLT:     displayIncRow ? displayIncRow.leadTime : '',
    incVolRfq:    displayIncRow ? displayIncRow.rfq : '',
    ltdBestVendor:   ltdRow ? ltdRow.vendor : '',
    ltdBestCost:     ltdRow ? ltdRow.cost : null,
    ltdBestQty:      ltdRow ? ltdRow.qty : null,
    ltdBestLeadTime: ltdRow ? ltdRow.leadTime : '',
    ltdBestLtNotes:  ltdRow ? ltdRow.leadTimeNotes : '',
    incAllVendors: [...incVendorSet].join(', '),
    ltdAllVendors: [...ltdVendorSet].join(', '),
    incOnlySuppliers: [...incVendorSet].filter(v => !ltdVendorSet.has(v)).join(', '),
    ltdOnlySuppliers: [...ltdVendorSet].filter(v => !incVendorSet.has(v)).join(', '),
    sharedSuppliers:  [...incVendorSet].filter(v => ltdVendorSet.has(v)).join(', '),
    cpcs: cpcs.join(', '), rfqLineIds: lineIds.join(', '), lineDescs: lineDescs.slice(0, 3).join(' | '),
    onAvl,
    qtyRatio: (displayIncRow && displayIncRow.qty && ltdQty) ? displayIncRow.qty / ltdQty : null,
  });
}
function incBreaksHas(k) { return incByMpn.has(k); }
function incBreaksByMpn(k) { return incByMpn.get(k).vendors; }

// ────────── summary stats ──────────
const cleanApples = rows.filter(r => r.bucketTag === 'CLEAN_APPLES');
const oranges     = rows.filter(r => r.bucketTag === 'ORANGES');
const stretch     = rows.filter(r => r.bucketTag === 'STRETCH');
const incOnly     = rows.filter(r => r.bucketTag === 'INC_ONLY');
const ltdOnly     = rows.filter(r => r.bucketTag === 'LTD_ONLY');

function bucketSpend(arr) {
  const incSpend = arr.reduce((s, r) => s + (r.incVolCost && r.demandQty ? r.incVolCost * r.demandQty : 0), 0);
  const ltdSpend = arr.reduce((s, r) => s + (r.ltdBestCost && r.demandQty ? r.ltdBestCost * r.demandQty : 0), 0);
  const bestSpend = arr.reduce((s, r) => s + (r.incVolCost && r.ltdBestCost && r.demandQty ? Math.min(r.incVolCost, r.ltdBestCost) * r.demandQty : 0), 0);
  const winCounts = { Inc: 0, Ltd: 0, TIE: 0 };
  for (const r of arr) if (winCounts[r.winner] !== undefined) winCounts[r.winner]++;
  return { incSpend, ltdSpend, bestSpend, winCounts };
}
const apOn  = bucketSpend(cleanApples.filter(r => r.onAvl));
const apOff = bucketSpend(cleanApples.filter(r => !r.onAvl));

// Ltd-only on-AVL/off-AVL spend
const ltdOnlyOnAvl = ltdOnly.filter(r => r.onAvl);
const ltdOnlyOffAvl = ltdOnly.filter(r => !r.onAvl);
const ltdOnlyOnAvlSpend = ltdOnlyOnAvl.reduce((s, r) => s + (r.ltdBestCost && r.demandQty ? r.ltdBestCost * r.demandQty : 0), 0);
const ltdOnlyOffAvlSpend = ltdOnlyOffAvl.reduce((s, r) => s + (r.ltdBestCost && r.demandQty ? r.ltdBestCost * r.demandQty : 0), 0);

// Inc-only on-AVL count
const incOnlyOnAvl = incOnly.filter(r => r.onAvl).length;
const incOnlyOffAvl = incOnly.length - incOnlyOnAvl;

// ────────── AVL Coverage % comparison ──────────
// Two granularities: (a) accepted-MPN level (1,485 entries in chuboe_rfq_line_mpn),
// (b) RFQ-line level (480 lines). For each, count Inc / Ltd / both / either / neither.
const totalLines = lineInfoById.size;
const totalAcceptedMpns = onAvlSet.size;

// Per accepted MPN — is it quoted on each side?
let incMpnCovAll = 0, incMpnCovApi = 0;
let ltdMpnCov = 0;
let bothMpnCovApi = 0, eitherMpnCovApi = 0;
for (const k of onAvlSet) {
  const incHasAll = incByMpn.has(k);
  // Inc API-only: at least one vendor on this MPN that's NOT a manual channel
  const incHasApi = incHasAll && [...incByMpn.get(k).vendors.keys()].some(v => !isManualIncChannel(v));
  const ltdHas = ltdByMpn.has(k);
  if (incHasAll) incMpnCovAll++;
  if (incHasApi) incMpnCovApi++;
  if (ltdHas) ltdMpnCov++;
  if (incHasApi && ltdHas) bothMpnCovApi++;
  if (incHasApi || ltdHas) eitherMpnCovApi++;
}

// Per RFQ line — does ANY accepted MPN on this line have a quote on each side?
const lineCov = { bothApi: 0, incOnlyApi: 0, ltdOnlyApi: 0, neither: 0, bothAll: 0, incOnlyAll: 0, ltdOnlyAll: 0, incAll: 0, ltdAll: 0, incApi: 0, ltdAll2: 0 };
const lineToAccepted = new Map();
for (const [k, list] of acceptedIdx) for (const e of list) {
  if (!lineToAccepted.has(e.lineId)) lineToAccepted.set(e.lineId, new Set());
  lineToAccepted.get(e.lineId).add(k);
}
for (const [lid, mpnSet] of lineToAccepted) {
  const anyIncAll = [...mpnSet].some(m => incByMpn.has(m));
  const anyIncApi = [...mpnSet].some(m => incByMpn.has(m) && [...incByMpn.get(m).vendors.keys()].some(v => !isManualIncChannel(v)));
  const anyLtd = [...mpnSet].some(m => ltdByMpn.has(m));
  if (anyIncAll) lineCov.incAll++;
  if (anyIncApi) lineCov.incApi++;
  if (anyLtd)    lineCov.ltdAll++;
  if (anyIncApi && anyLtd)  lineCov.bothApi++;
  else if (anyIncApi)       lineCov.incOnlyApi++;
  else if (anyLtd)          lineCov.ltdOnlyApi++;
  else                      lineCov.neither++;
  if (anyIncAll && anyLtd)  lineCov.bothAll++;
  else if (anyIncAll)       lineCov.incOnlyAll++;
  else if (anyLtd)          lineCov.ltdOnlyAll++;
}

console.log('\n══ AVL Coverage ══');
console.log(`RFQ lines total: ${totalLines}`);
console.log(`  Inc-side coverage (ALL VQs):   ${lineCov.incAll}/${totalLines}  (${(100*lineCov.incAll/totalLines).toFixed(1)}%)`);
console.log(`  Inc-side coverage (API-only):  ${lineCov.incApi}/${totalLines}  (${(100*lineCov.incApi/totalLines).toFixed(1)}%)   [excludes TI direct + Coilcraft manual]`);
console.log(`  Ltd-side coverage:             ${lineCov.ltdAll}/${totalLines}  (${(100*lineCov.ltdAll/totalLines).toFixed(1)}%)`);
console.log(`  Both (API-only Inc + Ltd):     ${lineCov.bothApi}`);
console.log(`  Inc-only (API): ${lineCov.incOnlyApi}, Ltd-only: ${lineCov.ltdOnlyApi}, Neither: ${lineCov.neither}`);
console.log(`Accepted MPNs total: ${totalAcceptedMpns}`);
console.log(`  Inc coverage (ALL):     ${incMpnCovAll}/${totalAcceptedMpns}  (${(100*incMpnCovAll/totalAcceptedMpns).toFixed(1)}%)`);
console.log(`  Inc coverage (API):     ${incMpnCovApi}/${totalAcceptedMpns}  (${(100*incMpnCovApi/totalAcceptedMpns).toFixed(1)}%)   [manual excluded]`);
console.log(`  Ltd coverage:           ${ltdMpnCov}/${totalAcceptedMpns}  (${(100*ltdMpnCov/totalAcceptedMpns).toFixed(1)}%)`);
console.log(`  Either side (API):      ${eitherMpnCovApi}/${totalAcceptedMpns}  (${(100*eitherMpnCovApi/totalAcceptedMpns).toFixed(1)}%)`);

console.log(`Both-side MPNs: ${cleanApples.length + oranges.length + stretch.length}`);
console.log(`  CLEAN apples : ${cleanApples.length}  (on-AVL ${cleanApples.filter(r=>r.onAvl).length} / off-AVL ${cleanApples.filter(r=>!r.onAvl).length})`);
