// ────────── MFR-region trends ──────────
// MFR Pricing Trends compares each side's BEST quote ACROSS ALL THEIR SUPPLIERS
// on a given MPN. That mixes two things:
//   1. TRUE PRICING — winner has a better price at a supplier the loser also has
//   2. COVERAGE     — winner has a supplier the loser doesn't, and that supplier
//                     was cheaper than anything the loser could reach
// For each clean apples row we now classify the win type by checking whether
// the winning side's best vendor is also in the loser's vendor set on that MPN.
function classifyWinType(r) {
  if (r.winner === 'TIE' || !r.winner || !r.bucketTag === 'CLEAN_APPLES') return 'N/A';
  const winningVendor = r.winner === 'Inc' ? r.incVolVendor : r.ltdBestVendor;
  const loserVendorList = r.winner === 'Inc' ? r.ltdAllVendors : r.incAllVendors;
  const loserSet = new Set(loserVendorList.split(/,\s*/).filter(Boolean));
  return loserSet.has(winningVendor) ? 'TRUE_PRICING' : 'COVERAGE';
}
for (const r of cleanApples) r.winType = classifyWinType(r);

const mfrAgg = new Map();
for (const r of cleanApples) {
  const mfr = r.mfrNorm || '(unknown)';
  if (!mfrAgg.has(mfr)) mfrAgg.set(mfr, {
    mpnCount: 0,
    incWins: 0, ltdWins: 0, ties: 0,
    incPricingWins: 0, incCoverageWins: 0,
    ltdPricingWins: 0, ltdCoverageWins: 0,
    savingsToLtd: 0, savingsToInc: 0,
    savingsLtdPricing: 0, savingsLtdCoverage: 0,
    savingsIncPricing: 0, savingsIncCoverage: 0,
    ltdWinChannels: new Map(), incWinChannels: new Map(),
    mpns: []
  });
  const a = mfrAgg.get(mfr);
  a.mpnCount++;
  a.mpns.push(r.mpn);
  if (r.winner === 'Inc') {
    a.incWins++;
    a.savingsToInc += r.savingsDollars || 0;
    a.incWinChannels.set(r.incVolVendor, (a.incWinChannels.get(r.incVolVendor) || 0) + 1);
    if (r.winType === 'TRUE_PRICING') { a.incPricingWins++; a.savingsIncPricing += r.savingsDollars || 0; }
    else if (r.winType === 'COVERAGE') { a.incCoverageWins++; a.savingsIncCoverage += r.savingsDollars || 0; }
  } else if (r.winner === 'Ltd') {
    a.ltdWins++;
    a.savingsToLtd += r.savingsDollars || 0;
    a.ltdWinChannels.set(r.ltdBestVendor, (a.ltdWinChannels.get(r.ltdBestVendor) || 0) + 1);
    if (r.winType === 'TRUE_PRICING') { a.ltdPricingWins++; a.savingsLtdPricing += r.savingsDollars || 0; }
    else if (r.winType === 'COVERAGE') { a.ltdCoverageWins++; a.savingsLtdCoverage += r.savingsDollars || 0; }
  } else if (r.winner === 'TIE') a.ties++;
}

console.log('\n══ MFR-region trends (clean apples) ══');
const mfrArr = [...mfrAgg.entries()].sort((a, b) => b[1].mpnCount - a[1].mpnCount);
console.log(`${'MFR'.padEnd(20)} ${'#'.padStart(4)} ${'Inc'.padStart(4)} ${'Ltd'.padStart(4)} ${'Tie'.padStart(4)} ${'Save→Ltd $'.padStart(12)} ${'Save→Inc $'.padStart(12)}  Dominant winning channel`);
for (const [mfr, a] of mfrArr.slice(0, 20)) {
  const topLtdCh = [...a.ltdWinChannels.entries()].sort((x, y) => y[1] - x[1]).slice(0, 1).map(([c, n]) => `Ltd via ${c} ×${n}`).join('');
  const topIncCh = [...a.incWinChannels.entries()].sort((x, y) => y[1] - x[1]).slice(0, 1).map(([c, n]) => `Inc via ${c} ×${n}`).join('');
  const dom = [topLtdCh, topIncCh].filter(Boolean).join(' | ');
  console.log(`${mfr.padEnd(20)} ${String(a.mpnCount).padStart(4)} ${String(a.incWins).padStart(4)} ${String(a.ltdWins).padStart(4)} ${String(a.ties).padStart(4)} $${a.savingsToLtd.toFixed(0).padStart(11)} $${a.savingsToInc.toFixed(0).padStart(11)}  ${dom}`);
}

// ────────── Same-supplier head-to-head + MFR breakdown ──────────
const sameSupplierRows = [];
for (const k of allMpns) {
  if (!incByMpn.has(k) || !ltdByMpn.has(k)) continue;
  const incSlot = incByMpn.get(k);
  const ltdSlot = ltdByMpn.get(k);
  const ltdByVendor = new Map();
  for (const r of ltdSlot.all) {
    if (!ltdByVendor.has(r.vendor) || r.cost < ltdByVendor.get(r.vendor).cost) ltdByVendor.set(r.vendor, r);
  }
  for (const vendor of [...incSlot.vendors.keys()].filter(v => ltdByVendor.has(v))) {
    const incRows = incSlot.vendors.get(vendor);
    const ltdRow = ltdByVendor.get(vendor);
    const ltdQty = ltdRow.qty || ltdRow.demand;
    const sorted = incRows.slice().sort((a, b) => a.qty - b.qty);
    let incRow = null, tag = 'STRETCH';
    if (ltdQty) {
      for (const r of sorted) { if (r.qty >= ltdQty * 0.95) { incRow = r; tag = 'VOLUME'; break; } }
    }
    if (!incRow) { incRow = sorted[sorted.length - 1]; tag = 'STRETCH'; }
    const ic = incRow.cost, lc = ltdRow.cost;
    const delta = lc - ic;
    const supWinner = Math.abs(delta) / Math.max(ic, lc) < 0.005 ? 'TIE' : (lc < ic ? 'Ltd' : 'Inc');
    const demandQty = ltdRow.demand || ltdRow.qty || 0;
    const savingsDollars = Math.abs(delta) * demandQty;
    sameSupplierRows.push({
      mpn: incSlot.rawMpn, mfgr: ltdRow.mfgr, mfrNorm: ltdRow.mfrNorm, description: ltdRow.description,
      demandQty, vendor, winner: supWinner, breakTag: tag,
      savingsPct: (Math.max(ic, lc) - Math.min(ic, lc)) / Math.max(ic, lc),
      savingsDollars,
      incCost: incRow.cost, incQty: incRow.qty, incLT: incRow.leadTime,
      ltdCost: ltdRow.cost, ltdQty: ltdRow.qty, ltdClass: ltdRow.leadClass, ltdLtNotes: ltdRow.leadTimeNotes,
      qtyRatio: (incRow.qty && ltdQty) ? incRow.qty / ltdQty : null,
      onAvl: onAvlSet.has(k)
    });
  }
}

// ────────── Supplier Profile ──────────
// For each shared supplier (both sides quoted this channel for at least one
// MPN), aggregate the head-to-head outcomes: how often is each side cheaper,
// median delta %, total $ at stake, and the net side advantage.
const supplierProfile = new Map(); // vendor → { n, incWins, ltdWins, ties, deltas:[], savingsLtd, savingsInc, savingsTotal, onAvlRows, onAvlSavings }
for (const r of sameSupplierRows) {
  if (!supplierProfile.has(r.vendor)) {
    supplierProfile.set(r.vendor, {
      n: 0, incWins: 0, ltdWins: 0, ties: 0, deltas: [],
      savingsLtd: 0, savingsInc: 0, savingsTotal: 0,
      onAvlRows: 0, onAvlSavings: 0,
      ltdMin: Infinity, ltdMax: -Infinity, incMin: Infinity, incMax: -Infinity
    });
  }
  const e = supplierProfile.get(r.vendor);
  e.n++;
  // signed delta: (Ltd - Inc) / Inc → negative means Ltd cheaper at this supplier
  if (r.incCost > 0) e.deltas.push((r.ltdCost - r.incCost) / r.incCost);
  if (r.winner === 'Inc') { e.incWins++; e.savingsInc += r.savingsDollars; e.savingsTotal += r.savingsDollars; }
  else if (r.winner === 'Ltd') { e.ltdWins++; e.savingsLtd += r.savingsDollars; e.savingsTotal += r.savingsDollars; }
  else e.ties++;
  if (r.onAvl) { e.onAvlRows++; e.onAvlSavings += r.savingsDollars; }
}
function median(arr) {
  if (!arr.length) return null;
  const s = arr.slice().sort((a, b) => a - b);
  const m = Math.floor(s.length / 2);
  return s.length % 2 ? s[m] : (s[m - 1] + s[m]) / 2;
}

// Side-level supplier profile: independent of "shared". For each side, count
// how often each supplier was the WINNING vendor across all clean-apples wins.
const incSideProfile = new Map(); // vendor → { winsOnInc, mpnsAppearedOnIncWins }
const ltdSideProfile = new Map();
for (const r of cleanApples) {
  if (r.winner === 'Inc' && r.incVolVendor) {
    if (!incSideProfile.has(r.incVolVendor)) incSideProfile.set(r.incVolVendor, { wins: 0, savings: 0 });
    const e = incSideProfile.get(r.incVolVendor);
    e.wins++; e.savings += r.savingsDollars || 0;
  } else if (r.winner === 'Ltd' && r.ltdBestVendor) {
    if (!ltdSideProfile.has(r.ltdBestVendor)) ltdSideProfile.set(r.ltdBestVendor, { wins: 0, savings: 0 });
    const e = ltdSideProfile.get(r.ltdBestVendor);
    e.wins++; e.savings += r.savingsDollars || 0;
  }
}

console.log('\n══ Supplier Profile (shared suppliers — same MPN both sides quoted) ══');
const profArr = [...supplierProfile.entries()].sort((a, b) => b[1].n - a[1].n);
console.log(`${'Supplier'.padEnd(42)} ${'N'.padStart(4)} ${'Inc'.padStart(4)} ${'Ltd'.padStart(4)} ${'Tie'.padStart(4)} ${'Median Δ%'.padStart(11)} ${'Save→Ltd $'.padStart(12)} ${'Save→Inc $'.padStart(12)}  Net`);
for (const [v, e] of profArr) {
  const med = median(e.deltas);
  const medStr = med == null ? '—' : `${med >= 0 ? '+' : ''}${(med * 100).toFixed(1)}%`;
  const netSide = e.savingsLtd > e.savingsInc * 1.1 ? 'LTD' : e.savingsInc > e.savingsLtd * 1.1 ? 'INC' : 'NEUTRAL';
  console.log(`${v.padEnd(42)} ${String(e.n).padStart(4)} ${String(e.incWins).padStart(4)} ${String(e.ltdWins).padStart(4)} ${String(e.ties).padStart(4)} ${medStr.padStart(11)} $${e.savingsLtd.toFixed(0).padStart(11)} $${e.savingsInc.toFixed(0).padStart(11)}  ${netSide}`);
}

// Same-supplier × MFR aggregation: which side wins on each (MFR, channel) pair?
const ssMfrChannel = new Map(); // "${mfr}||${vendor}" → {n, incWins, ltdWins, ties, savingsLtd, savingsInc}
for (const r of sameSupplierRows) {
  const key = `${r.mfrNorm}||${r.vendor}`;
  if (!ssMfrChannel.has(key)) ssMfrChannel.set(key, { mfr: r.mfrNorm, vendor: r.vendor, n: 0, incWins: 0, ltdWins: 0, ties: 0, savingsLtd: 0, savingsInc: 0 });
  const e = ssMfrChannel.get(key);
  e.n++;
  if (r.winner === 'Inc') { e.incWins++; e.savingsInc += r.savingsDollars; }
  else if (r.winner === 'Ltd') { e.ltdWins++; e.savingsLtd += r.savingsDollars; }
  else e.ties++;
}

