// Sub-classify off-AVL
const PKG_SUFFIXES = [/-CT-ND$/, /-CT$/, /-ND$/, /-TR$/, /-REEL$/, /-TUBE$/, /-TAPE$/, /-T\/R$/, /-B$/, /-BULK$/, /-BAG$/, /-AT$/];
const QUAL_SUFFIXES = [/#PBF$/, /#TRPBF$/, /-PBF$/, /_PBF$/, /Q1$/, /Q100$/, /-Q1$/, /G4$/, /E4$/, /-G4$/];
function classifyOffAvl(b) {
  const m = normMpn(b.mpn);
  for (const re of PKG_SUFFIXES) {
    const stripped = m.replace(re, '');
    if (stripped !== m && acceptedIdx.has(stripped)) return { cls: 'PACKAGING', base: stripped };
  }
  for (const re of QUAL_SUFFIXES) {
    const stripped = m.replace(re, '');
    if (stripped !== m && acceptedIdx.has(stripped)) return { cls: 'QUAL_VARIANT', base: stripped };
  }
  // Try packaging then qual
  for (const re of PKG_SUFFIXES) {
    const s1 = m.replace(re, '');
    if (s1 !== m) {
      for (const re2 of QUAL_SUFFIXES) {
        const s2 = s1.replace(re2, '');
        if (s2 !== s1 && acceptedIdx.has(s2)) return { cls: 'QUAL_VARIANT', base: s2 };
      }
    }
  }
  // Check MFR is on RFQ
  const allRfqMfrs = new Set();
  for (const list of acceptedIdx.values()) for (const x of list) if (x.mfr) allRfqMfrs.add(x.mfr);
  const bmfr = b.mfrNorm;
  // (we don't have rfq mfr per line easily here, so simplified)
  return { cls: 'CROSS_REF', base: '' };
}

